#!/usr/bin/env python3
"""
Bug #2601: jax.jit (XLA) produces wrong output vs PyTorch eager reference.

Patterns    : [['layout', 'resize_cubic_halfpixel'], ['layout', 'resize_linear_asymmetric'], ['broadcast', 'gelu_approx'], ['attention', 'matmul_4d_batch'], ['attention', 'matmul_4d_batch'], ['broadcast', 'mul_add_relu']]
Dependencies: numpy jax
Run         : python unique_2601.py  →  exit 0 = BUG REPRODUCED
"""
import sys
import numpy as np
import jax, jax.numpy as jnp
from jax import lax
import jax.scipy.special

# ── Model weights ─────────────────────────────────────────────────────────────
_w0 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([0])
_w1 = np.frombuffer(bytes.fromhex("0000803f0000803f0000004000000040"), dtype=np.float32).reshape([4])
_w2 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([0])
_w3 = np.frombuffer(bytes.fromhex("0000803f0000803f0000004000000040"), dtype=np.float32).reshape([4])
_w4 = np.frombuffer(bytes.fromhex("1327373d"), dtype=np.float32).reshape([1])
_w5 = np.frombuffer(bytes.fromhex("2a424c3f"), dtype=np.float32).reshape([1])
_w6 = np.frombuffer(bytes.fromhex("0000803f"), dtype=np.float32).reshape([1])
_w7 = np.frombuffer(bytes.fromhex("0000003f"), dtype=np.float32).reshape([1])
_w8 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 1, 128, 128])
_w9 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 1, 128, 128])
_w10 = np.frombuffer(bytes.fromhex("0000803f0000803f0000803f"), dtype=np.float32).reshape([1, 3, 1, 1])
_w11 = np.frombuffer(bytes.fromhex("000000000000000000000000"), dtype=np.float32).reshape([1, 3, 1, 1])

# ── Triggering input ─────────────────────────────────────────────────────────
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 3, 32, 32])  # input "model_input"

EXPECTED = np.frombuffer(bytes.fromhex(""), dtype=np.float32)  # pytorch_eager reference


# ── Model computation (translated from ONNX) ──────────────────────────────────
def model(x):
    n0_resi_out = (lambda _x, _sc: jnp.transpose(jax.image.resize(jnp.transpose(_x,(0,2,3,1)), (int(_x.shape[0]), int(_x.shape[2]*_sc[2]), int(_x.shape[3]*_sc[3]), int(_x.shape[1])), method='linear'), (0,3,1,2)))(x, _w1)
    n100_resi_out = (lambda _x, _sc: jnp.transpose(jax.image.resize(jnp.transpose(_x,(0,2,3,1)), (int(_x.shape[0]), int(_x.shape[2]*_sc[2]), int(_x.shape[3]*_sc[3]), int(_x.shape[1])), method='linear'), (0,3,1,2)))(n0_resi_out, _w3)
    n200_gelu_x2 = n100_resi_out * n100_resi_out
    n200_gelu_x3 = n200_gelu_x2 * n100_resi_out
    n200_gelu_sc = n200_gelu_x3 * _w4
    n200_gelu_inn = n100_resi_out + n200_gelu_sc
    n200_gelu_mlt = n200_gelu_inn * _w5
    n200_gelu_th = jnp.tanh(n200_gelu_mlt)
    n200_gelu_add = n200_gelu_th + _w6
    n200_gelu_hf = n100_resi_out * _w7
    n200_gelu_out = n200_gelu_hf * n200_gelu_add
    n300_mm4d_out = jnp.matmul(n200_gelu_out, _w8)
    n400_mm4d_out = jnp.matmul(n300_mm4d_out, _w9)
    n500_mar_mul = n400_mm4d_out * _w10
    n500_mar_add = n500_mar_mul + _w11
    n500_mar_out = jnp.maximum(n500_mar_add, np.float32(0.0))
    return jnp.asarray(n500_mar_out, dtype=jnp.float32)


if __name__ == "__main__":
    x_jax = jnp.array(INPUT)
    out = np.array(jax.jit(model)(x_jax), dtype=np.float32).ravel()

    diff = float(np.linalg.norm(EXPECTED.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(EXPECTED.astype(np.float64)) + 1e-8))
    print(f"expected (pytorch_eager): {EXPECTED[:6]}")
    print(f"actual   (jax.jit/XLA) : {out[:6]}")
    print(f"rel L2 : {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
